class Tarjan:
    def __init__(self, n):
        self.n = n
        self.graph = [[] for _ in range(n)]

        self.ids = [-1] * n
        self.low_links = [-1] * n
        self.on_stack = [False] * n
        self.stack = []
        self.time = 0
        self.sccs = []

    def add_edge(self, u, v):
        self.graph[u].append(v)

    def find_sccs(self):
        for i in range(self.n):
            if self.ids[i] == -1:
                self._dfs(i)
        return self.sccs

    def _dfs(self, u):
        self.ids[u] = self.time
        self.low_links[u] = self.time
        self.time += 1

        self.stack.append(u)
        self.on_stack[u] = True

        for v in self.graph[u]:
            if self.ids[v] == -1:
                self._dfs(v)
                self.low_links[u] = min(self.low_links[u], self.low_links[v])
            elif self.on_stack[v]:
                self.low_links[u] = min(self.low_links[u], self.ids[v])

        if self.ids[u] == self.low_links[u]:
            current_scc = []
            while True:
                node = self.stack.pop()
                self.on_stack[node] = False
                current_scc.append(node)
                if node == u:
                    break
            self.sccs.append(current_scc)
